ion Theorem. It contains a 3 Ampere current source on the left, connected to a parallel branch. The top branch goes through a 2 Ohm resistor (labeled 'A'), then to node B. A 1.5 Ohm resistor is in parallel with this section, connected from the top branch after the 3 Amp source to the bottom wire. From node B, there's another 2 Ohm resistor in the main path (branch AB), leading to a 15V voltage source (positive up). A 5 Ohm resistor connects node B to the bottom wire (common ground).", "question_text": "Find the value of current in branch AB by using Super position Theorem.", "image_strategy": "CANVAS", "recreated_image_url": "https://s3.us-east-005.backblazeb2.com/campusprep/recreated/942386d7-fe0b-4ecf-af71-b780e1813b64.png?X-Amz-Algorithm=AWS4-HMAC-SHA256&X-Amz-Credential=005ff988bd983190000000001%2F20260226%2Fus-east-005%2Fs3%2Faws4_request&X-Amz-Date=20260226T030945Z&X-Amz-Expires=3600&X-Amz-SignedHeaders=host&X-Amz-Signature=c9856906ba098162df3c092c9a1ef930fe8269e3f49bb81646d3dbd55df909ab", "recreated_html_source": "<canvas id=\\"canvas\\"></canvas>\\n<script>\\n(() => {\\n  const canvas = document.getElementById('canvas');\\n  const ctx = canvas.getContext('2d');\\n\\n  // Logical size\\n  const logicalWidth = 800;\\n  const logicalHeight = 600;\\n\\n  // Adjust for high DPI displays\\n  const dpr = window.devicePixelRatio || 1;\\n  canvas.width = logicalWidth * dpr;\\n  canvas.height = logicalHeight * dpr;\\n  canvas.style.width = logicalWidth + 'px';\\n  canvas.style.height = logicalHeight + 'px';\\n  ctx.scale(dpr, dpr);\\n\\n  // Styling\\n  const wireColor = '#475569';      // slate-700\\n  const resistorColor = '#4f46e5';  // indigo-600\\n  const sourceColor = '#10b981';    // emerald-500\\n  const textColor = '#111827';      // gray-900\\n  ctx.lineCap = 'round';\\n  ctx.font = '14px sans-serif';\\n  ctx.textAlign = 'center';\\n  ctx.textBaseline = 'middle';\\n\\n  // Helper functions\\n  function drawLine(x1, y1, x2, y2, color = wireColor, width = 2) {\\n    ctx.strokeStyle = color;\\n    ctx.lineWidth = width;\\n    ctx.beginPath();\\n    ctx.moveTo(x1, y1);\\n    ctx.lineTo(x2, y2);\\n    ctx.stroke();\\n  }\\n\\n  function drawResistor(x, y, length, horizontal = true, label = '') {\\n    const zigzagSize = 6;\\n    const segments = 6; // number of zigzag peaks\\n    const step = length / (segments * 2);\\n    ctx.strokeStyle = resistorColor;\\n    ctx.lineWidth = 2;\\n    ctx.beginPath();\\n    ctx.moveTo(x, y);\\n    for (let i = 0; i < segments * 2; i++) {\\n      const dx = horizontal ? step : 0;\\n      const dy = horizontal ? 0 : step;\\n      const offset = (i % 2 === 0) ? zigzagSize : -zigzagSize;\\n      if (horizontal) {\\n        ctx.lineTo(x + (i + 1) * step, y + offset);\\n      } else {\\n        ctx.lineTo(x + offset, y + (i + 1) * step);\\n      }\\n    }\\n    ctx.lineTo(x + (horizontal ? length : 0), y + (horizontal ? 0 : length));\\n    ctx.stroke();\\n\\n    // label\\n    if (label) {\\n      ctx.fillStyle = textColor;\\n      ctx.fillText(label, x + length / 2, y - (horizontal ? 20 : 0) + (horizontal ? 0 : length / 2));\\n    }\\n  }\\n\\n  function drawCurrentSource(x, y, length, label = '') {\\n    const radius = 15;\\n    // wires\\n    drawLine(x - length / 2, y, x - radius, y);\\n    drawLine(x + radius, y, x + length / 2, y);\\n    // circle\\n    ctx.strokeStyle = sourceColor;\\n    ctx.lineWidth = 2;\\n    ctx.beginPath();\\n    ctx.arc(x, y, radius, 0, Math.PI * 2);\\n    ctx.stroke();\\n    // arrow (rightward)\\n    ctx.fillStyle = sourceColor;\\n    ctx.beginPath();\\n    ctx.moveTo(x - 5, y - 8);\\n    ctx.lineTo(x + 12, y);\\n    ctx.lineTo(x - 5, y + 8);\\n    ctx.closePath();\\n    ctx.fill();\\n    // label\\n    if (label) {\\n      ctx.fillStyle = textColor;\\n      ctx.fillText(label, x, y - 30);\\n    }\\n  }\\n\\n  function drawVoltageSource(x, y, length, label = '') {\\n    const radius = 15;\\n    // wires\\n    drawLine(x - length / 2, y, x - radius, y);\\n    drawLine(x + radius, y, x + length / 2, y);\\n    // circle\\n    ctx.strokeStyle = sourceColor;\\n    ctx.lineWidth = 2;\\n    ctx.beginPath();\\n    ctx.arc(x, y, radius, 0, Math.PI * 2);\\n    ctx.stroke();\\n    // plus sign (top)\\n    ctx.strokeStyle = sourceColor;\\n    ctx.lineWidth = 2;\\n    ctx.beginPath();\\n    ctx.moveTo(x, y - 8);\\n    ctx.lineTo(x, y - 2);\\n    ctx.moveTo(x - 3, y - 5);\\n    ctx.lineTo(x + 3, y - 5);\\n    ctx.stroke();\\n    // minus sign (bottom)\\n    ctx.beginPath();\\n    ctx.moveTo(x - 5, y + 5);\\n    ctx.lineTo(x + 5, y + 5);\\n    ctx.stroke();\\n    // label\\n    if (label) {\\n      ctx.fillStyle = textColor;\\n      ctx.fillText(label, x, y - 30);\\n    }\\n  }\\n\\n  function drawGround(x, y) {\\n    const gap = 4;\\n    const width = 20;\\n    ctx.strokeStyle = wireColor;\\n    ctx.lineWidth = 2;\\n    ctx.beginPath();\\n    ctx.moveTo(x, y);\\n    ctx.lineTo(x, y + gap);\\n    ctx.moveTo(x - width / 2, y + gap);\\n    ctx.lineTo(x + width / 2, y + gap);\\n    ctx.moveTo(x - width / 3, y + gap + 4);\\n    ctx.lineTo(x + width / 3, y + gap + 4);\\n    ctx.moveTo(x - width / 6, y + gap + 8);\\n    ctx.lineTo(x + width / 6, y + gap + 8);\\n    ctx.stroke();\\n  }\\n\\n  // Coordinates\\n  const startX = 100;\\n  const startY = 300;\\n\\n  // 1. Current source (3 A)\\n  drawCurrentSource(startX, startY, 80, '3 A');\\n\\n  // Node after source\\n  const nodeX = startX + 80;\\n  const nodeY = startY;\\n\\n  // Horizontal wire to the right (main line)\\n  const nodeB_X = nodeX + 200;\\n  drawLine(nodeX, nodeY, nodeB_X, nodeY);\\n\\n  // 2. Top branch: resistor A (2 Ω) from nodeX up to nodeB\\n  const topY = nodeY - 120;\\n  drawLine(nodeX, nodeY, nodeX, topY); // up\\n  drawResistor(nodeX, topY, nodeB_X - nodeX, true, '2 Ω (A)'); // horizontal on top\\n  drawLine(nodeB_X, topY, nodeB_X, nodeY); // down\\n\\n  // 3. Bottom branch: 1.5 Ω resistor from nodeX down to ground\\n  const groundY = nodeY + 150;\\n  drawLine(nodeX, nodeY, nodeX, groundY - 30); // down to resistor top\\n  drawResistor(nodeX, groundY - 30, 60, false, '1.5 Ω');\\n  drawLine(nodeX, groundY + 30, nodeX, groundY + 30); // short wire after resistor\\n  drawGround(nodeX, groundY + 30);\\n\\n  // 4. At node B: 5 Ω resistor to ground\\n  drawLine(nodeB_X, nodeY, nodeB_X, groundY - 30);\\n  drawResistor(nodeB_X, groundY - 30, 60, false, '5 Ω');\\n  drawGround(nodeB_X, groundY + 30);\\n\\n  // 5. Series 2 Ω resistor from node B to voltage source\\n  const afterRes_X = nodeB_X + 120;\\n  drawResistor(nodeB_X, nodeY, afterRes_X - nodeB_X, true, '2 Ω');\\n\\n  // 6. 15 V voltage source (positive up)\\n  const vs_X = afterRes_X + 80;\\n  drawVoltageSource(vs_X, nodeY, 80, '15 V');\\n\\n  // 7. Rightmost wire (open circuit)\\n  drawLine(vs_X + 40, nodeY, vs_X + 120, nodeY);\\n})();\\n</script>"}, {"part": "b", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "Define the average value, RMS value form factor, and peak factor of an AC quantity. How are these parameters calculated for a sinusoidal waveform?", "image_strategy": null}, {"part": "a", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "A coil of resistance $100\\\\Omega$ and inductance $0.1H$ is connected in series with $150pF$ capacitor across a $200V$, $50Hz$ supply calculate:\\n\\ni) Inductive reactance\\n\\nii) Capacitive reactance\\n\\niii) Impedance\\n\\niv) Current\\n\\nv) Power factor\\n\\nvi) Voltage across coil\\n\\nvii) Voltage across capacitor", "image_strategy": null}, {"part": "b", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "A $3-\\\\phi$ balanced system supplies $110V$ to a delta connected load whose phase impedance is equal to $(3.54 + j3.54)\\\\Omega$. Determine the line current and draw the phasor diagram.", "image_strategy": null}, {"part": "a", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "What do you understand by self inductance and mutual inductance? Derive the relation between self inductance and mutual inductance.", "image_strategy": null}, {"part": "b", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "Discuss about the laws of electromagnetic Induction.", "image_strategy": null}, {"part": "a", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "The open circuit and short circuit tests on a single phase transformer gave the following results:\\n\\n$V_0 = 200V, I_0 = 0.7A, W_0 = 20$ watt on primary side.\\n\\n$V_s = 10V, I_s = 10A, W_s = 40$ watt on secondary side.\\n\\nDetermine the equivalent circuit parameters referred to primary side.", "image_strategy": null}, {"part": "b", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "Discuss the construction and working principle of the three phase induction motor. Draw the torque slip characteristic of the above. Why this motor cannot operate on synchronous speed?", "image_strategy": null}, {"part": "a", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "Describe D.C. machine with suitable sketches in viewing of main parts and construction details:", "image_strategy": null}, {"part": "b", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "A three phase $440$ volt, $50$ hp, $50$ Hz induction motor delivers rated output power at $1440$ rpm. Find the following:\\n\\ni) No of poles of machine\\n\\nii) Synchronous speed\\n\\niii) Slip\\n\\niv) Slip rpm\\n\\nv) Rotor speed w.r.t\\n\\nvi) If the stator to rotor turn ratio is $1:0.5$, then rotor emf at operating speed. Assume winding factor is unity.", "image_strategy": null}, {"part": "a", "unit": null, "marks": 14, "has_or_choice": false, "image_details": null, "question_text": "Solve for x\\n\\ni) $(257)_8 = (x)_2$\\n\\nii) $(21.625)_{10} = (x)_8$\\n\\niii) $(BC.2)_{16} = (x)_{10}$", "image_strategy": null}, {"part": "a", "unit": null, "marks": 7, "has_or_choice": true, "image_details": null, "question_text": "Star Delta Transformation", "image_strategy": null}, {"part": "b", "unit": null, "marks": 7, "has_or_choice": true, "image_details": null, "question_text": "J-K Flip-Flop", "image_strategy": null}, {"part": "c", "unit": null, "marks": 7, "has_or_choice": true, "image_details": null, "question_text": "Magnetization Characteristics of Ferromagnetic Material", "image_strategy": null}, {"part": "d", "unit": null, "marks": 7, "has_or_choice": true, "image_details": null, "question_text": "Power in balanced and Unbalanced Three Phase System", "image_strategy": null}]}	t	NATIVE	f	\N	2026-02-25 16:01:50.14497+00	2026-02-26 03:09:46.04065+00
