113	UNSOLVED_PYQ	Strength of Materials - Nov 2022	2022	You are an elite expert AI parser specializing in Engineering Academic exams for RGPV University.\n\nCONTEXT:\nBuilding material for Branch: {branch_name}\nSubject: {subject_code} - {subject_name}\nDocument Type target: {document_type}\n\nYour task is to extract exact information from raw exam papers, syllabi, or notes (provided as text or images) and generate pristine, highly-accurate structured data for them.\nYou MUST output valid JSON conforming strictly to the requested schema.\nCRITICAL INSTRUCTION: DO NOT process or transcribe any Hindi text whatsoever. Extract and process ONLY the English versions of the questions.\nIMAGE INSTRUCTION: If a question or section does NOT contain an image or diagram in the source, set 'image_strategy' to null and 'image_details' to null. DO NOT invent or assume images exist.\nFor 'latex_answer' or any mathematical fields, use Markdown for normal text and wrap ANY math in KaTeX delimiters ($ for inline, $$ for block formulas).	raw_docs/ce-305-strength-of-materials-nov-2022.pdf	\N	COMPLETED	1	1	0	1	{"questions": [{"part": "a", "unit": null, "marks": 2, "has_or_choice": false, "image_details": null, "question_text": "A circular steel bar of length 'L' cross-sectional area 'A' and weight 'W' is fixed at its upper end and hangs vertically. Find the elongation of the bar under its own weight.", "image_strategy": null}, {"part": "b", "unit": null, "marks": 6, "has_or_choice": false, "image_details": null, "question_text": "A steel rod of 25 mm diameter and 2 meter length is subjected to an axial pull of 45 kN. Find:\\ni) Intensity of stress\\nii) Stress\\niii) Elongation\\nTake E = $2 \\\\times 10^5$ N/mm$^2$.", "image_strategy": null}, {"part": "c", "unit": null, "marks": 6, "has_or_choice": false, "image_details": null, "question_text": "A straight bar 450 mm long is 20 mm in diameter for the first 250 mm length and 10 mm diameter for the remaining length. If the bar is subjected to an axial pull of 10 kN. Find the extension of the bar. Take E = $2 \\\\times 10^5$ N/mm$^2$.", "image_strategy": null}, {"part": null, "unit": null, "marks": 14, "has_or_choice": false, "image_details": null, "question_text": "A rectangular block of material is subjected to a tensile stress of 110 N/mm$^2$ on one plane and a tensile stress of 47 N/mm$^2$ on a plane at right angle, together with shear stresses of 63 N/mm$^2$ on the same planes. Find:\\ni) The direction of the principal planes.\\nii) The magnitude of the principal stress.\\niii) The magnitude of the greatest shear stress.", "image_strategy": null}, {"part": "a", "unit": null, "marks": 7, "has_or_choice": false, "image_details": "A simply supported beam of total length 4m. It has a support at the left end (A) and a support at 3m from A (let's call it B). The beam extends 1m beyond B. A point load of 3 kN acts downwards at 1m from A. A uniformly distributed load of 2 kN/m acts downwards from 2m from A to the right end of the beam (i.e., over the last 2m of the beam).", "question_text": "Draw the shear force and bending moment diagrams for a beam supported and loaded as shown in figure.", "image_strategy": "CANVAS", "recreated_image_url": "https://s3.us-east-005.backblazeb2.com/campusprep/recreated/f2f4b0ad-0927-421f-bb0d-dca1fbc8101a.png?X-Amz-Algorithm=AWS4-HMAC-SHA256&X-Amz-Credential=005ff988bd983190000000001%2F20260225%2Fus-east-005%2Fs3%2Faws4_request&X-Amz-Date=20260225T191817Z&X-Amz-Expires=3600&X-Amz-SignedHeaders=host&X-Amz-Signature=bcc98e2a55918ad740e305911f8d56ce8cff0c0d6cb2e2cc7676a6ad5271ec07", "recreated_html_source": "<canvas id=\\"canvas\\"></canvas>\\n<script>\\nconst canvas = document.getElementById('canvas');\\nconst ctx = canvas.getContext('2d');\\n\\n// logical dimensions (meters)\\nconst L = 4;               // total length\\nconst supportBPos = 3;     // position of support B from A\\nconst pointLoadPos = 1;    // position of point load from A\\nconst udlStart = 2;        // start of uniformly distributed load\\nconst udlEnd = L;          // end of udl (right end)\\n\\n// visual scaling\\nconst pxPerM = 200;        // horizontal scale (200 px per metre)\\nconst beamY = 150;         // vertical position of beam centre\\nconst beamThickness = 6;\\nconst supportSize = 30;    // size of support symbols\\nconst loadArrowSize = 20;  // length of load arrows\\nconst textOffset = 10;\\n\\n// set canvas size\\ncanvas.width = L * pxPerM + 100;   // extra margin\\ncanvas.height = 250;\\n\\n// colours\\nconst colors = {\\n  beam: '#374151',      // slate-700\\n  support: '#4F46E5',   // indigo-600\\n  pointLoad: '#10B981', // emerald-500\\n  udl: '#10B981',       // emerald-500\\n  text: '#111827'      // slate-900\\n};\\n\\n// helper to convert metres to canvas x‑coordinate\\nfunction x(m) { return 50 + m * pxPerM; }\\n\\n// draw beam\\nfunction drawBeam() {\\n  ctx.strokeStyle = colors.beam;\\n  ctx.lineWidth = beamThickness;\\n  ctx.beginPath();\\n  ctx.moveTo(x(0), beamY);\\n  ctx.lineTo(x(L), beamY);\\n  ctx.stroke();\\n}\\n\\n// draw pin support (triangle) at A\\nfunction drawPinSupport(pos) {\\n  const cx = x(pos);\\n  const cy = beamY + beamThickness/2;\\n  ctx.fillStyle = colors.support;\\n  ctx.beginPath();\\n  ctx.moveTo(cx, cy);\\n  ctx.lineTo(cx - supportSize/2, cy + supportSize);\\n  ctx.lineTo(cx + supportSize/2, cy + supportSize);\\n  ctx.closePath();\\n  ctx.fill();\\n}\\n\\n// draw roller support (circle on top of triangle) at B\\nfunction drawRollerSupport(pos) {\\n  const cx = x(pos);\\n  const cy = beamY + beamThickness/2;\\n  // triangle base\\n  ctx.fillStyle = colors.support;\\n  ctx.beginPath();\\n  ctx.moveTo(cx, cy);\\n  ctx.lineTo(cx - supportSize/2, cy + supportSize);\\n  ctx.lineTo(cx + supportSize/2, cy + supportSize);\\n  ctx.closePath();\\n  ctx.fill();\\n  // rollers (three small circles)\\n  const r = 5;\\n  const offset = 8;\\n  ctx.fillStyle = colors.support;\\n  for (let i = -1; i <= 1; i++) {\\n    ctx.beginPath();\\n    ctx.arc(cx + i*offset, cy + supportSize + r + 2, r, 0, Math.PI*2);\\n    ctx.fill();\\n  }\\n}\\n\\n// draw point load arrow\\nfunction drawPointLoad(pos, magnitude) {\\n  const cx = x(pos);\\n  const top = beamY - loadArrowSize - 20;\\n  ctx.strokeStyle = colors.pointLoad;\\n  ctx.fillStyle = colors.pointLoad;\\n  ctx.lineWidth = 2;\\n  // arrow shaft\\n  ctx.beginPath();\\n  ctx.moveTo(cx, beamY);\\n  ctx.lineTo(cx, top);\\n  ctx.stroke();\\n  // arrow head\\n  ctx.beginPath();\\n  ctx.moveTo(cx - 6, top + 6);\\n  ctx.lineTo(cx, top);\\n  ctx.lineTo(cx + 6, top + 6);\\n  ctx.fill();\\n  // label\\n  ctx.fillStyle = colors.text;\\n  ctx.font = '14px sans-serif';\\n  ctx.textAlign = 'center';\\n  ctx.fillText(`${magnitude} kN`, cx, top - textOffset);\\n}\\n\\n// draw uniformly distributed load as a series of arrows\\nfunction drawUDL(start, end, intensity) {\\n  const step = 0.3; // metres between arrows\\n  const arrowHeight = loadArrowSize;\\n  ctx.strokeStyle = colors.udl;\\n  ctx.fillStyle = colors.udl;\\n  ctx.lineWidth = 2;\\n  for (let m = start; m <= end; m += step) {\\n    const cx = x(m);\\n    const top = beamY - arrowHeight - 20;\\n    // shaft\\n    ctx.beginPath();\\n    ctx.moveTo(cx, beamY);\\n    ctx.lineTo(cx, top);\\n    ctx.stroke();\\n    // head\\n    ctx.beginPath();\\n    ctx.moveTo(cx - 5, top + 5);\\n    ctx.lineTo(cx, top);\\n    ctx.lineTo(cx + 5, top + 5);\\n    ctx.fill();\\n  }\\n  // bracket and label\\n  const leftX = x(start);\\n  const rightX = x(end);\\n  const bracketY = beamY - arrowHeight - 40;\\n  ctx.strokeStyle = colors.text;\\n  ctx.lineWidth = 1;\\n  ctx.beginPath();\\n  ctx.moveTo(leftX, bracketY);\\n  ctx.lineTo(leftX, bracketY + 10);\\n  ctx.moveTo(rightX, bracketY);\\n  ctx.lineTo(rightX, bracketY + 10);\\n  ctx.moveTo(leftX, bracketY + 5);\\n  ctx.lineTo(rightX, bracketY + 5);\\n  ctx.stroke();\\n  ctx.fillStyle = colors.text;\\n  ctx.font = '14px sans-serif';\\n  ctx.textAlign = 'center';\\n  ctx.fillText(`${intensity} kN/m`, (leftX + rightX)/2, bracketY - 5);\\n}\\n\\n// draw dimension lines\\nfunction drawDimension(start, end, label, yPos) {\\n  const sx = x(start);\\n  const ex = x(end);\\n  const offset = yPos;\\n  ctx.strokeStyle = colors.text;\\n  ctx.lineWidth = 1;\\n  ctx.beginPath();\\n  ctx.moveTo(sx, offset);\\n  ctx.lineTo(ex, offset);\\n  ctx.moveTo(sx, offset - 5);\\n  ctx.lineTo(sx, offset + 5);\\n  ctx.moveTo(ex, offset - 5);\\n  ctx.lineTo(ex, offset + 5);\\n  ctx.stroke();\\n  ctx.fillStyle = colors.text;\\n  ctx.font = '13px sans-serif';\\n  ctx.textAlign = 'center';\\n  ctx.fillText(label, (sx + ex)/2, offset - 8);\\n}\\n\\n// ---- drawing sequence ----\\ndrawBeam();\\ndrawPinSupport(0);          // support A at x=0\\ndrawRollerSupport(supportBPos); // support B at x=3 m\\ndrawPointLoad(pointLoadPos, 3);\\ndrawUDL(udlStart, udlEnd, 2);\\n\\n// dimensions\\ndrawDimension(0, pointLoadPos, '1 m', beamY + 60);\\ndrawDimension(pointLoadPos, supportBPos, '2 m', beamY + 80);\\ndrawDimension(supportBPos, L, '1 m (overhang)', beamY + 100);\\n</script>"}, {"part": "b", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "Derive the relation between the rate of loading, shear force and bending moment.", "image_strategy": null}, {"part": null, "unit": null, "marks": 14, "has_or_choice": false, "image_details": null, "question_text": "A beam of length 'L' simply supported at the ends carries a point load 'W' at a distance 'a' from the left end. Find the deflection under the load and the maximum deflection using Macaulay's method.", "image_strategy": null}, {"part": null, "unit": null, "marks": 14, "has_or_choice": false, "image_details": null, "question_text": "Find the Euler's critical load for a hollow cylindrical cast iron column 200 mm external diameter and 25 mm thick, if it is 6 meter long and hinged at both ends. Take E = $8 \\\\times 10^4$ N/mm$^2$. Compare Euler's Critical load with the Rankine's critical load taking $f_c = 550$ N/mm$^2$ and $a = 1/1600$. For what length of column Euler's critical loads by Euler's and Rankine's formula will be equal?", "image_strategy": null}, {"part": "a", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "Explain in detail St. Venant Theory.", "image_strategy": null}, {"part": "b", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "A air vessel of a torpedo is 530 mm external diameter and 10 mm thick, the length being 1830 mm. Find the change in the external diameter and the length when charged to 10.5 N/mm$^2$ internal pressure. Take E = $2.1 \\\\times 10^5$ N/mm$^2$ and Poisson's ratio = 0.3.", "image_strategy": null}, {"part": null, "unit": null, "marks": 14, "has_or_choice": false, "image_details": null, "question_text": "A solid shaft is to transmit 337.5 kW at 120 r.p.m. If the shear stress of the material must not exceed 80 N/mm$^2$. Find the required diameter.", "image_strategy": null}, {"part": null, "unit": null, "marks": 14, "has_or_choice": false, "image_details": null, "question_text": "A beam AB 10 meters long has supports at its ends A and B. It carried a point load of 5 kN at 3 meters from A and a point load of 5 kN at 7 meters from A and a uniformly distributed load of 1 kN per meter between the point loads. Draw SF and BM diagrams for the beam.", "image_strategy": null}]}	t	NATIVE	f	\N	2026-02-25 16:01:50.146931+00	2026-02-25 17:32:45.977054+00
