charset=\\"UTF-8\\">\\n<title>Data Structure Classification Diagram</title>\\n<style>\\n  body{margin:0;padding:0;display:flex;justify-content:center;align-items:center;height:100vh;background:#f5f5f5;}\\n  #canvas{border:1px solid #ccc;max-width:100%;height:auto;}\\n</style>\\n</head>\\n<body>\\n<canvas id=\\"canvas\\"></canvas>\\n<script>\\nconst canvas = document.getElementById('canvas');\\nconst ctx = canvas.getContext('2d');\\n\\n// logical size (in CSS pixels)\\nconst LOGICAL_WIDTH = 900;\\nconst LOGICAL_HEIGHT = 620;\\n\\n// handle high‑DPI screens\\nconst dpr = window.devicePixelRatio || 1;\\ncanvas.width = LOGICAL_WIDTH * dpr;\\ncanvas.height = LOGICAL_HEIGHT * dpr;\\ncanvas.style.width = LOGICAL_WIDTH + 'px';\\ncanvas.style.height = LOGICAL_HEIGHT + 'px';\\nctx.scale(dpr, dpr);\\n\\n// common styles\\nctx.font = '14px Arial';\\nctx.textBaseline = 'top';\\nctx.lineWidth = 2;\\nctx.strokeStyle = '#333';\\nctx.fillStyle = '#fff';\\n\\n// colour palette\\nconst colors = {\\n  slate: '#708090',\\n  indigo: '#4B0082',\\n  emerald: '#50C878',\\n  lightSlate: '#A0B0C0',\\n  lightIndigo: '#7A5FA0',\\n  lightEmerald: '#7FD9A5'\\n};\\n\\n// helper to draw a labelled box\\nfunction drawBox(x, y, w, h, title, items, bg) {\\n  // background\\n  ctx.fillStyle = bg;\\n  ctx.fillRect(x, y, w, h);\\n  // border\\n  ctx.strokeStyle = '#333';\\n  ctx.strokeRect(x, y, w, h);\\n  // title\\n  ctx.fillStyle = '#fff';\\n  ctx.font = 'bold 16px Arial';\\n  ctx.textAlign = 'center';\\n  ctx.fillText(title, x + w / 2, y + 6);\\n  // items\\n  ctx.font = '14px Arial';\\n  ctx.textAlign = 'left';\\n  const lineHeight = 18;\\n  items.forEach((it, i) => {\\n    ctx.fillText('• ' + it, x + 8, y + 30 + i * lineHeight);\\n  });\\n}\\n\\n// positions\\nconst startX = 50;\\nconst startY = 30;\\nconst boxW = 180;\\nconst boxH = 120;\\nconst vGap = 80;\\nconst hGap = 30;\\n\\n// Root\\ndrawBox(startX + (LOGICAL_WIDTH - boxW) / 2, startY, boxW, 60,\\n  'Data Structures', [], colors.slate);\\n\\n// Primitive\\ndrawBox(startX, startY + 80, boxW, boxH,\\n  'Primitive', ['int', 'char', 'float', 'bool'], colors.indigo);\\n\\n// Non‑Primitive\\ndrawBox(startX + LOGICAL_WIDTH - boxW - startX, startY + 80, boxW, boxH,\\n  'Non‑Primitive', [], colors.indigo);\\n\\n// Linear\\ndrawBox(startX + (LOGICAL_WIDTH - boxW) / 2 - boxW/2 - hGap/2,\\n  startY + 80 + boxH + vGap, boxW, boxH,\\n  'Linear', [], colors.emerald);\\n\\n// Non‑Linear\\ndrawBox(startX + (LOGICAL_WIDTH - boxW) / 2 + boxW/2 + hGap/2,\\n  startY + 80 + boxH + vGap, boxW, boxH,\\n  'Non‑Linear', [], colors.emerald);\\n\\n// Static\\ndrawBox(startX + (LOGICAL_WIDTH - boxW) / 2 - boxW - hGap,\\n  startY + 80 + 2*boxH + 2*vGap, boxW, boxH,\\n  'Static', ['Array', 'Static List'], colors.lightEmerald);\\n\\n// Dynamic\\ndrawBox(startX + (LOGICAL_WIDTH - boxW) / 2 + hGap,\\n  startY + 80 + 2*boxH + 2*vGap, boxW, boxH,\\n  'Dynamic', ['Linked List', 'Stack', 'Queue', 'Tree'], colors.lightEmerald);\\n\\n// Non‑Linear examples\\ndrawBox(startX + LOGICAL_WIDTH - boxW - startX,\\n  startY + 80 + boxH + vGap, boxW, boxH,\\n  'Non‑Linear', ['Tree', 'Graph', 'Heap'], colors.lightIndigo);\\n\\n// Connectors\\nctx.strokeStyle = '#555';\\nctx.lineWidth = 1.5;\\n\\n// root to primitive & non‑primitive\\nctx.beginPath();\\nctx.moveTo(LOGICAL_WIDTH/2, startY + 60);\\nctx.lineTo(startX + boxW/2, startY + 80);\\nctx.moveTo(LOGICAL_WIDTH/2, startY + 60);\\nctx.lineTo(LOGICAL_WIDTH - startX - boxW/2, startY + 80);\\nctx.stroke();\\n\\n// primitive to linear\\nctx.beginPath();\\nctx.moveTo(startX + boxW, startY + 80 + boxH);\\nctx.lineTo(startX + (LOGICAL_WIDTH - boxW) / 2 - boxW/2 - hGap/2, startY + 80 + boxH + vGap);\\nctx.stroke();\\n\\n// non‑primitive to linear & non‑linear\\nctx.beginPath();\\nctx.moveTo(LOGICAL_WIDTH - startX - boxW, startY + 80 + boxH);\\nctx.lineTo(startX + (LOGICAL_WIDTH - boxW) / 2 - boxW/2 - hGap/2, startY + 80 + boxH + vGap);\\nctx.moveTo(LOGICAL_WIDTH - startX - boxW, startY + 80 + boxH);\\nctx.lineTo(startX + (LOGICAL_WIDTH - boxW) / 2 + boxW/2 + hGap/2, startY + 80 + boxH + vGap);\\nctx.stroke();\\n\\n// linear to static & dynamic\\nctx.beginPath();\\nctx.moveTo(startX + (LOGICAL_WIDTH - boxW) / 2 - boxW/2 - hGap/2 + boxW, startY + 80 + boxH + vGap);\\nctx.lineTo(startX + (LOGICAL_WIDTH - boxW) / 2 - boxW - hGap/2, startY + 80 + 2*boxH + 2*vGap);\\nctx.moveTo(startX + (LOGICAL_WIDTH - boxW) / 2 - boxW/2 - hGap/2, startY + 80 + boxH + vGap);\\nctx.lineTo(startX + (LOGICAL_WIDTH - boxW) / 2 + hGap, startY + 80 + 2*boxH + 2*vGap);\\nctx.stroke();\\n\\n// non‑linear examples line\\nctx.beginPath();\\nctx.moveTo(startX + (LOGICAL_WIDTH - boxW) / 2 + boxW/2 + hGap/2, startY + 80 + boxH + vGap);\\nctx.lineTo(LOGICAL_WIDTH - startX - boxW/2, startY + 80 + boxH + vGap);\\nctx.stroke();\\n</script>\\n</body>\\n</html>"}, {"part": null, "unit": 1, "marks": 14, "has_or_choice": true, "image_details": null, "question_text": "What is asymptotic analysis? Explain Big-O notation. Analyze and write the running time complexity of the following function.\\n\\n```c\\nA(){\\n    int i, j, k, n;\\n    for(i=1; i<=n; i++)\\n        for(j=1; j<=n; j++)\\n            for(k=1; 2k<=n; k++)\\n                printf(\\"*\\");\\n}\\n```", "image_strategy": null}, {"part": "a", "unit": 2, "marks": 14, "has_or_choice": false, "image_details": null, "question_text": "Given an array with both positive and negative numbers, find the two elements such that their sum is closest to zero. For the below array, algorithm should give -80 and 85. Example: $1, 60, -10, 70, -80, 85$\\nAlso discuss the complexity of the process and suggest and alternate way to optimize the complexity.", "image_strategy": null}, {"part": "a", "unit": 2, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "What is a link list? Discuss the advantages of using link list; also write about the various operations which can be performed on link list with their time complexities.", "image_strategy": null}, {"part": "b", "unit": 2, "marks": 7, "has_or_choice": false, "image_details": "Diagram showing two singly linked lists intersecting at some point and merging into a single linked list. The first list has nodes pointing to the second list's nodes, which then continue as a single list ending in NULL.", "question_text": "Suppose there are two singly linked lists both of which intersect at some point and become a single linked list as shown below:\\n\\nThe head pointers of both the lists are known. Give an algorithm for finding the merging point and write the running time complexity.", "image_strategy": "CANVAS", "recreated_image_url": "https://s3.us-east-005.backblazeb2.com/campusprep/recreated/bace1db5-079a-4437-be42-5e1b412ce9ee.png?X-Amz-Algorithm=AWS4-HMAC-SHA256&X-Amz-Credential=005ff988bd983190000000001%2F20260225%2Fus-east-005%2Fs3%2Faws4_request&X-Amz-Date=20260225T191843Z&X-Amz-Expires=3600&X-Amz-SignedHeaders=host&X-Amz-Signature=0a63cc8d1fb54892a0a202025bcc75595588a60609b30b69b34dd28d6ffd0d34", "recreated_html_source": "<canvas id=\\"canvas\\"></canvas>\\n<script>\\n(() => {\\n  const canvas = document.getElementById('canvas');\\n  const ctx = canvas.getContext('2d');\\n\\n  // Set canvas size (responsive to window width)\\n  function resizeCanvas() {\\n    const dpr = window.devicePixelRatio || 1;\\n    const width = Math.min(window.innerWidth * 0.95, 900);\\n    const height = 300;\\n    canvas.style.width = width + 'px';\\n    canvas.style.height = height + 'px';\\n    canvas.width = width * dpr;\\n    canvas.height = height * dpr;\\n    ctx.scale(dpr, dpr);\\n    drawDiagram();\\n  }\\n\\n  // Utility: draw a node (rounded rectangle) with label\\n  function drawNode(x, y, w, h, label, fillStyle) {\\n    const radius = 6;\\n    ctx.fillStyle = fillStyle;\\n    ctx.strokeStyle = '#333';\\n    ctx.lineWidth = 1.5;\\n    ctx.beginPath();\\n    ctx.moveTo(x + radius, y);\\n    ctx.lineTo(x + w - radius, y);\\n    ctx.quadraticCurveTo(x + w, y, x + w, y + radius);\\n    ctx.lineTo(x + w, y + h - radius);\\n    ctx.quadraticCurveTo(x + w, y + h, x + w - radius, y + h);\\n    ctx.lineTo(x + radius, y + h);\\n    ctx.quadraticCurveTo(x, y + h, x, y + h - radius);\\n    ctx.lineTo(x, y + radius);\\n    ctx.quadraticCurveTo(x, y, x + radius, y);\\n    ctx.closePath();\\n    ctx.fill();\\n    ctx.stroke();\\n\\n    // Text\\n    ctx.fillStyle = '#fff';\\n    ctx.font = '14px sans-serif';\\n    ctx.textAlign = 'center';\\n    ctx.textBaseline = 'middle';\\n    ctx.fillText(label, x + w / 2, y + h / 2);\\n  }\\n\\n  // Utility: draw an arrow from (x1,y1) to (x2,y2)\\n  function drawArrow(x1, y1, x2, y2, color) {\\n    const headLen = 10; // length of head in pixels\\n    const angle = Math.atan2(y2 - y1, x2 - x1);\\n    ctx.strokeStyle = color;\\n    ctx.fillStyle = color;\\n    ctx.lineWidth = 2;\\n    ctx.beginPath();\\n    ctx.moveTo(x1, y1);\\n    ctx.lineTo(x2, y2);\\n    ctx.stroke();\\n\\n    // arrowhead\\n    ctx.beginPath();\\n    ctx.moveTo(x2, y2);\\n    ctx.lineTo(x2 - headLen * Math.cos(angle - Math.PI / 6),\\n               y2 - headLen * Math.sin(angle - Math.PI / 6));\\n    ctx.lineTo(x2 - headLen * Math.cos(angle + Math.PI / 6),\\n               y2 - headLen * Math.sin(angle + Math.PI / 6));\\n    ctx.lineTo(x2, y2);\\n    ctx.closePath();\\n    ctx.fill();\\n  }\\n\\n  function drawDiagram() {\\n    ctx.clearRect(0, 0, canvas.width, canvas.height);\\n    const nodeW = 80, nodeH = 30, gapX = 120, gapY = 80;\\n    const startX = 60, startY = 60;\\n\\n    // Colors\\n    const slate = '#65748b';\\n    const indigo = '#5c6ac4';\\n    const emerald = '#34d399';\\n\\n    // First list (List A) nodes\\n    const a1 = {x: startX, y: startY};\\n    const a2 = {x: a1.x + gapX, y: a1.y};\\n    const a3 = {x: a2.x + gapX, y: a2.y};\\n\\n    // Second list (List B) nodes (starts lower)\\n    const b1 = {x: startX, y: startY + gapY};\\n    const b2 = {x: b1.x + gapX, y: b1.y};\\n\\n    // Intersection node (shared)\\n    const c1 = {x: a3.x + gapX, y: a3.y}; // same as continuation start\\n    const c2 = {x: c1.x + gapX, y: c1.y};\\n    const c3 = {x: c2.x + gapX, y: c2.y};\\n\\n    // Draw nodes\\n    drawNode(a1.x, a1.y, nodeW, nodeH, 'A1', slate);\\n    drawNode(a2.x, a2.y, nodeW, nodeH, 'A2', slate);\\n    drawNode(a3.x, a3.y, nodeW, nodeH, 'A3', slate);\\n\\n    drawNode(b1.x, b1.y, nodeW, nodeH, 'B1', indigo);\\n    drawNode(b2.x, b2.y, nodeW, nodeH, 'B2', indigo);\\n\\n    drawNode(c1.x, c1.y, nodeW, nodeH, 'C1', emerald);\\n    drawNode(c2.x, c2.y, nodeW, nodeH, 'C2', emerald);\\n    drawNode(c3.x, c3.y, nodeW, nodeH, 'C3', emerald);\\n\\n    // Draw NULL terminator\\n    ctx.fillStyle = '#555';\\n    ctx.font = '14px sans-serif';\\n    ctx.textAlign = 'left';\\n    ctx.textBaseline = 'middle';\\n    ctx.fillText('NULL', c3.x + nodeW + 15, c3.y + nodeH / 2);\\n\\n    // Arrows for List A\\n    drawArrow(a1.x + nodeW, a1.y + nodeH / 2, a2.x, a2.y + nodeH / 2, slate);\\n    drawArrow(a2.x + nodeW, a2.y + nodeH / 2, a3.x, a3.y + nodeH / 2, slate);\\n    drawArrow(a3.x + nodeW, a3.y + nodeH / 2, c1.x, c1.y + nodeH / 2, slate);\\n\\n    // Arrows for List B\\n    drawArrow(b1.x + nodeW, b1.y + nodeH / 2, b2.x, b2.y + nodeH / 2, indigo);\\n    drawArrow(b2.x + nodeW, b2.y + nodeH / 2, c1.x, c1.y + nodeH / 2, indigo);\\n\\n    // Arrows for merged part\\n    drawArrow(c1.x + nodeW, c1.y + nodeH / 2, c2.x, c2.y + nodeH / 2, emerald);\\n    drawArrow(c2.x + nodeW, c2.y + nodeH / 2, c3.x, c3.y + nodeH / 2, emerald);\\n    drawArrow(c3.x + nodeW, c3.y + nodeH / 2, c3.x + nodeW + 10, c3.y + nodeH / 2, emerald);\\n  }\\n\\n  // Initial draw\\n  resizeCanvas();\\n\\n  // Redraw on resize\\n  window.addEventListener('resize', resizeCanvas);\\n})();\\n</script>"}, {"part": "a", "unit": 3, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "Define Stack. What are the different operations, which can be performed on stack. Explain why Stack is a recursive data structure?", "image_strategy": null}, {"part": "b", "unit": 3, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "Write an algorithm for evaluating a postfix expression and apply the same for the given postfix expression: $284-5*+77/+$, showing the content of stack at each step.", "image_strategy": null}, {"part": "a", "unit": 3, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "Explain the importance of queue. Describe why it is a bad idea to implement a linked list version a queue which uses the head of the list as the rear of the queue.", "image_strategy": null}, {"part": "b", "unit": 3, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "What is the advantage of circular queue over ordinary queue? Write a C program to simulate the working of circular queue of integers using array. Provide the following operations:\\ni) Insert\\nii) Delete\\niii) Display", "image_strategy": null}, {"part": "a", "unit": 5, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "Show the steps of quick sort on the following set of elements.\\n$26, 56, 47, 36, 13, 95, 85, 32$\\nAssume the last element as the pivot element.", "image_strategy": null}, {"part": "b", "unit": 3, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "Design a data representation which sequentially map 'n' data objects into an array $a[1, n]$, of these data objects are stacks and the remaining are queues. Write algorithms to add and delete elements from these objects.", "image_strategy": null}, {"part": "a", "unit": 5, "marks": 14, "has_or_choice": false, "image_details": null, "question_text": "What is collision? What are the methods to resolves collision? Using the hash function 'key mod 7', insert the following sequence of keys in the hash table-\\n$32, 50, 700, 140, 76, 85, 46, 92, 70, 73$ and $101$\\nUse separate chaining technique for collision resolution.", "image_strategy": null}, {"part": "a", "unit": 4, "marks": 7, "has_or_choice": false, "image_details": "A tree diagram with nodes labeled 'a', 'b', 'c', 'd', 'e', 'f', 'g', 'h', 'i', 'j'. The root is 'j'. 'j' has children 'f' and 'c'. 'f' has children 'd' and 'g'. 'c' has children 'e' and 'a'. 'e' has child 'h'. 'a' has child 'i'. 'i' has child 'b'.", "question_text": "What is the sequence of nodes visited for the following tree for a preorder, postorder, and breadth first traversal?", "image_strategy": "CANVAS", "recreated_image_url": "https://s3.us-east-005.backblazeb2.com/campusprep/recreated/6ec70b69-0d73-4a97-86e1-d8ae814c16a4.png?X-Amz-Algorithm=AWS4-HMAC-SHA256&X-Amz-Credential=005ff988bd983190000000001%2F20260225%2Fus-east-005%2Fs3%2Faws4_request&X-Amz-Date=20260225T191842Z&X-Amz-Expires=3600&X-Amz-SignedHeaders=host&X-Amz-Signature=c05ba0d2fa1803212028f9a5fd2dc31c55d365550cd373afea76d9d341031822", "recreated_html_source": "<canvas id=\\"canvas\\" style=\\"width:100%; max-width:800px; border:1px solid #ccc;\\"></canvas>\\n<script>\\n(() => {\\n  const canvas = document.getElementById('canvas');\\n  const ctx = canvas.getContext('2d');\\n\\n  // logical size (pixel‑perfect)\\n  const LOGICAL_WIDTH = 800;\\n  const LOGICAL_HEIGHT = 500;\\n  canvas.width = LOGICAL_WIDTH;\\n  canvas.height = LOGICAL_HEIGHT;\\n\\n  // styling\\n  const nodeRadius = 24;\\n  const nodeFill = '#607d8b';      // slate\\n  const nodeStroke = '#3f51b5';    // indigo\\n  const nodeTextColor = '#ffffff';\\n  const lineColor = '#3f51b5';\\n  const font = '16px sans-serif';\\n\\n  // node definitions (x, y, label)\\n  const nodes = {\\n    j: {x:400, y:50,  label:'j'},\\n    f: {x:250, y:150, label:'f'},\\n    c: {x:550, y:150, label:'c'},\\n    d: {x:150, y:250, label:'d'},\\n    g: {x:350, y:250, label:'g'},\\n    e: {x:450, y:250, label:'e'},\\n    a: {x:650, y:250, label:'a'},\\n    h: {x:450, y:350, label:'h'},\\n    i: {x:650, y:350, label:'i'},\\n    b: {x:650, y:450, label:'b'}\\n  };\\n\\n  // edges as [parentKey, childKey]\\n  const edges = [\\n    ['j','f'], ['j','c'],\\n    ['f','d'], ['f','g'],\\n    ['c','e'], ['c','a'],\\n    ['e','h'],\\n    ['a','i'],\\n    ['i','b']\\n  ];\\n\\n  // draw edges\\n  ctx.strokeStyle = lineColor;\\n  ctx.lineWidth = 2;\\n  edges.forEach(([pKey, cKey]) => {\\n    const p = nodes[pKey];\\n    const c = nodes[cKey];\\n    ctx.beginPath();\\n    ctx.moveTo(p.x, p.y + nodeRadius);\\n    ctx.lineTo(c.x, c.y - nodeRadius);\\n    ctx.stroke();\\n  });\\n\\n  // draw nodes\\n  ctx.font = font;\\n  ctx.textAlign = 'center';\\n  ctx.textBaseline = 'middle';\\n  Object.values(nodes).forEach(node => {\\n    // circle\\n    ctx.beginPath();\\n    ctx.arc(node.x, node.y, nodeRadius, 0, Math.PI*2);\\n    ctx.fillStyle = nodeFill;\\n    ctx.fill();\\n    ctx.strokeStyle = nodeStroke;\\n    ctx.lineWidth = 2;\\n    ctx.stroke();\\n\\n    // label\\n    ctx.fillStyle = nodeTextColor;\\n    ctx.fillText(node.label, node.x, node.y);\\n  });\\n})();\\n</script>"}, {"part": "b", "unit": 4, "marks": 7, "has_or_choice": false, "image_details": "A graph diagram with nodes 'a', 'b', 'e', 'f', 'h', 'g'. Edges connect: (a,b), (a,e), (a,f), (b,e), (b,h), (f,h), (h,g), (e,g).", "question_text": "What is Graph traversal? Discuss the difference between traversing a graph and a tree. Consider the following graph.\\n\\nAmong the following sequences, which are the depth-first traversal for the above graph? Justify your answer for traversals with adjacency list and stack content.\\ni) abcghf\\nii) abfehg\\niii) abfhgc\\niv) afghbc", "image_strategy": "CANVAS", "recreated_image_url": "https://s3.us-east-005.backblazeb2.com/campusprep/recreated/4fee232a-af7d-4c0d-9968-7f663b5251b0.png?X-Amz-Algorithm=AWS4-HMAC-SHA256&X-Amz-Credential=005ff988bd983190000000001%2F20260225%2Fus-east-005%2Fs3%2Faws4_request&X-Amz-Date=20260225T191842Z&X-Amz-Expires=3600&X-Amz-SignedHeaders=host&X-Amz-Signature=44f8fb5a2d7485eda593f7833d4bf57bea65c48e6f35e671af299cf0bd306ad4", "recreated_html_source": "<div style=\\"max-width:600px; margin:auto; padding:20px;\\">\\n  <canvas id=\\"canvas\\" style=\\"width:100%; height:auto; display:block;\\"></canvas>\\n</div>\\n<script>\\n  (function() {\\n    const canvas = document.getElementById('canvas');\\n    const ctx = canvas.getContext('2d');\\n\\n    // Logical canvas size (vector‑like coordinates)\\n    const LOGICAL_WIDTH = 500;\\n    const LOGICAL_HEIGHT = 400;\\n\\n    // Node definitions (positions in logical coordinates)\\n    const nodes = [\\n      { id: 'a', x: 100, y: 100 },\\n      { id: 'b', x: 400, y: 100 },\\n      { id: 'e', x: 150, y: 200 },\\n      { id: 'f', x: 350, y: 200 },\\n      { id: 'h', x: 350, y: 300 },\\n      { id: 'g', x: 150, y: 300 }\\n    ];\\n\\n    // Edge list (by node id)\\n    const edges = [\\n      ['a','b'], ['a','e'], ['a','f'],\\n      ['b','e'], ['b','h'],\\n      ['f','h'],\\n      ['h','g'],\\n      ['e','g']\\n    ];\\n\\n    // Styling\\n    const nodeRadius = 20;\\n    const nodeFill = '#708090';      // slate\\n    const nodeStroke = '#4B0082';    // indigo\\n    const edgeColor = '#50C878';     // emerald\\n    const fontFamily = 'Arial, Helvetica, sans-serif';\\n    const fontSize = 14;\\n    const fontColor = '#ffffff';\\n\\n    // Resize canvas to match container while keeping high‑DPI crispness\\n    function resizeCanvas() {\\n      const rect = canvas.getBoundingClientRect();\\n      const dpr = window.devicePixelRatio || 1;\\n      canvas.width = rect.width * dpr;\\n      canvas.height = rect.height * dpr;\\n      ctx.scale(dpr, dpr);\\n      draw();\\n    }\\n\\n    // Convert logical coordinates to actual pixel coordinates\\n    function toScreen(coord) {\\n      const rect = canvas.getBoundingClientRect();\\n      const scaleX = rect.width / LOGICAL_WIDTH;\\n      const scaleY = rect.height / LOGICAL_HEIGHT;\\n      return {\\n        x: coord.x * scaleX,\\n        y: coord.y * scaleY\\n      };\\n    }\\n\\n    function drawEdge(p1, p2) {\\n      const a = toScreen(p1);\\n      const b = toScreen(p2);\\n      ctx.beginPath();\\n      ctx.moveTo(a.x, a.y);\\n      ctx.lineTo(b.x, b.y);\\n      ctx.strokeStyle = edgeColor;\\n      ctx.lineWidth = 2;\\n      ctx.stroke();\\n    }\\n\\n    function drawNode(node) {\\n      const pos = toScreen(node);\\n      // Circle\\n      ctx.beginPath();\\n      ctx.arc(pos.x, pos.y, nodeRadius, 0, Math.PI * 2);\\n      ctx.fillStyle = nodeFill;\\n      ctx.fill();\\n      ctx.strokeStyle = nodeStroke;\\n      ctx.lineWidth = 2;\\n      ctx.stroke();\\n\\n      // Label\\n      ctx.font = `${fontSize}px ${fontFamily}`;\\n      ctx.fillStyle = fontColor;\\n      ctx.textAlign = 'center';\\n      ctx.textBaseline = 'middle';\\n      ctx.fillText(node.id, pos.x, pos.y);\\n    }\\n\\n    function draw() {\\n      // Clear\\n      ctx.clearRect(0, 0, canvas.width, canvas.height);\\n\\n      // Draw edges first\\n      edges.forEach(pair => {\\n        const n1 = nodes.find(n => n.id === pair[0]);\\n        const n2 = nodes.find(n => n.id === pair[1]);\\n        if (n1 && n2) drawEdge(n1, n2);\\n      });\\n\\n      // Draw nodes on top\\n      nodes.forEach(drawNode);\\n    }\\n\\n    // Initial size\\n    resizeCanvas();\\n\\n    // Redraw on window resize\\n    window.addEventListener('resize', resizeCanvas);\\n  })();\\n</script>"}]}	t	NATIVE	f	\N	2026-02-25 16:01:50.146931+00	2026-02-25 17:36:18.633931+00
52	UNSOLVED_PYQ	Basic Electrical and Electronics Engineering - Nov 2022	2022	You are an elite expert AI parser specializing in Engineering Academic exams for RGPV University.\n\nCONTEXT:\nBuilding material for Branch: {branch_name}\nSubject: {subject_code} - {subject_name}\nDocument Type target: {document_type}\n\nYour task is to extract exact information from raw exam papers, syllabi, or notes (provided as text or images) and generate pristine, highly-accurate structured data for them.\nYou MUST output valid JSON conforming strictly to the requested schema.\nCRITICAL INSTRUCTION: DO NOT process or transcribe any Hindi text whatsoever. Extract and process ONLY the English versions of the questions.\nIMAGE INSTRUCTION: If a question or section does NOT contain an image or diagram in the source, set 'image_strategy' to null and 'image_details' to null. DO NOT invent or assume images exist.\nFor 'latex_answer' or any mathematical fields, use Markdown for normal text and wrap ANY math in KaTeX delimiters ($ for inline, $$ for block formulas).	raw_docs/bt-104-basic-electrical-and-electronics-engineering-nov-2022.pdf	\N	COMPLETED	1	1	0	1	{"questions": [{"part": "a", "unit": null, "marks": 7, "has_or_choice": false, "image_details": "A circuit diagram with an 18V voltage source in series with a 1 Ohm resistor. This branch is in parallel with a 3A current source, which is in parallel with a dependent voltage source of 2Vx. The 2Vx source is in series with a 6 Ohm resistor. Vx is the voltage across the 1 Ohm resistor. Points 'a' and 'd' are marked.", "question_text": "Find the voltage $V_{ab}$ in the network shown below.", "image_strategy": "CANVAS", "recreated_image_url": "https://s3.us-east-005.backblazeb2.com/campusprep/recreated/37231ce7-4525-432f-9491-c4ceff526701.png?X-Amz-Algorithm=AWS4-HMAC-SHA256&X-Amz-Credential=005ff988bd983190000000001%2F20260225%2Fus-east-005%2Fs3%2Faws4_request&X-Amz-Date=20260225T170606Z&X-Amz-Expires=3600&X-Amz-SignedHeaders=host&X-Amz-Signature=85cc4dd7fb1061436422337ec009f515eaaf7242044822fb068d1e8a59f97cda", "recreated_html_source": "<canvas id=\\"canvas\\"></canvas>\\n<script>\\nconst canvas = document.getElementById('canvas');\\nconst dpr = window.devicePixelRatio || 1;\\nconst logicalWidth = 800;\\nconst logicalHeight = 300;\\ncanvas.width = logicalWidth * dpr;\\ncanvas.height = logicalHeight * dpr;\\ncanvas.style.width = logicalWidth + 'px';\\ncanvas.style.height = logicalHeight + 'px';\\nconst ctx = canvas.getContext('2d');\\nctx.scale(dpr, dpr);\\n\\n// ---------- Style ----------\\nconst lineColor = '#475569';      // slate-700\\nconst voltageColor = '#6366F1';   // indigo-500\\nconst currentColor = '#10B981';   // emerald-500\\nconst resistorColor = '#34D399';  // emerald-400\\nconst textColor = '#111827';      // gray-900\\nctx.lineWidth = 2;\\nctx.font = '14px sans-serif';\\nctx.textAlign = 'center';\\nctx.textBaseline = 'middle';\\n\\n// ---------- Geometry ----------\\nconst margin = 80;\\nconst topY = 80;\\nconst bottomY = 220;\\nconst nodeA_X = margin;\\nconst nodeD_X = logicalWidth - margin;\\nconst branchSpacing = (nodeD_X - nodeA_X) / 4;\\n\\n// ---------- Helper drawing ----------\\nfunction drawLine(x1, y1, x2, y2, color=lineColor) {\\n    ctx.strokeStyle = color;\\n    ctx.beginPath();\\n    ctx.moveTo(x1, y1);\\n    ctx.lineTo(x2, y2);\\n    ctx.stroke();\\n}\\nfunction drawResistor(x, y, length=40, orientation='vertical') {\\n    ctx.strokeStyle = resistorColor;\\n    const zigzag = 6;\\n    const step = length / (zigzag * 2);\\n    ctx.beginPath();\\n    if (orientation === 'vertical') {\\n        ctx.moveTo(x, y);\\n        for (let i = 0; i < zigzag; i++) {\\n            const dx = (i % 2 === 0) ? -8 : 8;\\n            ctx.lineTo(x + dx, y + step * (2*i+1));\\n            ctx.lineTo(x, y + step * (2*i+2));\\n        }\\n    } else {\\n        ctx.moveTo(x, y);\\n        for (let i = 0; i < zigzag; i++) {\\n            const dy = (i % 2 === 0) ? -8 : 8;\\n            ctx.lineTo(x + step * (2*i+1), y + dy);\\n            ctx.lineTo(x + step * (2*i+2), y);\\n        }\\n    }\\n    ctx.stroke();\\n}\\nfunction drawVoltageSource(x, y, radius=15, polarity='up') {\\n    ctx.strokeStyle = voltageColor;\\n    ctx.beginPath();\\n    ctx.arc(x, y, radius, 0, Math.PI*2);\\n    ctx.stroke();\\n    // plus/minus\\n    ctx.fillStyle = voltageColor;\\n    ctx.font = '12px sans-serif';\\n    if (polarity === 'up') {\\n        ctx.fillText('+', x, y - 6);\\n        ctx.fillText('−', x, y + 6);\\n    } else {\\n        ctx.fillText('+', x, y + 6);\\n        ctx.fillText('−', x, y - 6);\\n    }\\n}\\nfunction drawCurrentSource(x, y, radius=15) {\\n    ctx.strokeStyle = currentColor;\\n    ctx.beginPath();\\n    ctx.arc(x, y, radius, 0, Math.PI*2);\\n    ctx.stroke();\\n    // arrow\\n    ctx.fillStyle = currentColor;\\n    ctx.beginPath();\\n    ctx.moveTo(x, y - radius + 4);\\n    ctx.lineTo(x - 5, y - radius + 12);\\n    ctx.lineTo(x + 5, y - radius + 12);\\n    ctx.closePath();\\n    ctx.fill();\\n    ctx.fillText('3 A', x, y + radius - 12);\\n}\\n\\n// ---------- Draw outer nodes ----------\\ndrawLine(nodeA_X, topY, nodeD_X, topY);      // top wire (node a)\\ndrawLine(nodeA_X, bottomY, nodeD_X, bottomY); // bottom wire (node d)\\n\\n// ---------- Branch positions ----------\\nconst branchX = [\\n    nodeA_X + branchSpacing,          // 18 V + 1 Ω\\n    nodeA_X + 2*branchSpacing,        // 3 A current source\\n    nodeA_X + 3*branchSpacing         // 2 Vx + 6 Ω\\n];\\n\\n// ---------- Branch 1: 18 V source + 1 Ω resistor ----------\\ndrawLine(branchX[0], topY, branchX[0], bottomY); // vertical line placeholder\\ndrawVoltageSource(branchX[0], topY + 30, 15, 'up');\\ndrawLine(branchX[0], topY + 45, branchX[0], topY + 70);\\ndrawResistor(branchX[0], topY + 70, 40, 'vertical');\\ndrawLine(branchX[0], topY + 110, branchX[0], bottomY);\\nctx.fillStyle = textColor;\\nctx.fillText('18 V', branchX[0], topY + 15);\\nctx.fillText('1 Ω', branchX[0], topY + 95);\\nctx.fillText('Vₓ', branchX[0], topY + 115); // label Vx across resistor\\n\\n// ---------- Branch 2: 3 A current source ----------\\ndrawLine(branchX[1], topY, branchX[1], bottomY);\\ndrawCurrentSource(branchX[1], (topY + bottomY)/2);\\nctx.fillText('3 A', branchX[1], (topY + bottomY)/2 - 20);\\n\\n// ---------- Branch 3: 2 Vₓ dependent source + 6 Ω resistor ----------\\ndrawLine(branchX[2], topY, branchX[2], bottomY);\\ndrawVoltageSource(branchX[2], topY + 30, 15, 'up');\\nctx.fillStyle = voltageColor;\\nctx.fillText('2 Vₓ', branchX[2], topY + 15);\\ndrawLine(branchX[2], topY + 45, branchX[2], topY + 70);\\ndrawResistor(branchX[2], topY + 70, 40, 'vertical');\\ndrawLine(branchX[2], topY + 110, branchX[2], bottomY);\\nctx.fillStyle = textColor;\\nctx.fillText('6 Ω', branchX[2], topY + 95);\\n\\n// ---------- Node labels ----------\\nctx.fillStyle = textColor;\\nctx.font = '16px sans-serif';\\nctx.fillText('a', nodeA_X - 20, topY);\\nctx.fillText('d', nodeD_X + 20, bottomY);\\n\\n// ---------- Optional: arrows indicating direction of current (for illustration) ----------\\nfunction drawArrow(x1, y1, x2, y2) {\\n    const headlen = 8;\\n    const angle = Math.atan2(y2 - y1, x2 - x1);\\n    ctx.strokeStyle = lineColor;\\n    ctx.beginPath();\\n    ctx.moveTo(x1, y1);\\n    ctx.lineTo(x2, y2);\\n    ctx.stroke();\\n    ctx.beginPath();\\n    ctx.moveTo(x2, y2);\\n    ctx.lineTo(x2 - headlen * Math.cos(angle - Math.PI/6),\\n               y2 - headlen * Math.sin(angle - Math.PI/6));\\n    ctx.lineTo(x2 - headlen * Math.cos(angle + Math.PI/6),\\n               y2 - headlen * Math.sin(angle + Math.PI/6));\\n    ctx.lineTo(x2, y2);\\n    ctx.fillStyle = lineColor;\\n    ctx.fill();\\n}\\n// Example current direction from left to right on top wire\\ndrawArrow(nodeA_X + 10, topY - 20, nodeD_X - 10, topY - 20);\\nctx.fillStyle = textColor;\\nctx.fillText('I', (nodeA_X + nodeD_X)/2, topY - 30);\\n</script>"}, {"part": "b", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "Find the current through $6\\\\Omega$ resistor using Thevenin's theorem. (Refer to the network diagram provided for Q1.a)", "image_strategy": null}, {"part": "a", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "Draw Phasor diagrams of the following circuits.\\n\\ni) Series R-L-C when $X_L > X_C$.\\nii) Series R-L-C when $X_L < X_C$.\\niii) Series R-L-C when $X_L = X_C$.", "image_strategy": null}, {"part": "b", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "A 3-$\\\\phi$ balanced system supplies $110V$ to a delta connected load whose phase impedance is equal to $(3.54+j3.54)\\\\Omega$. Determine the line currents and draw the Phasor diagram.", "image_strategy": null}, {"part": "b", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "A $220\\\\,V$, $100\\\\,Hz$, A.C. source supplies a series RLC circuit with a capacitor and a coil. If the coil has $50\\\\,mH$ inductance, find at a resonance frequency of $100\\\\,Hz$, what is the value of capacitor?", "image_strategy": null}, {"part": "a", "unit": null, "marks": 7, "has_or_choice": false, "image_details": "Typical normal magnetization curve (B-H curve) for a ferromagnetic material, showing saturation.", "question_text": "Draw the typical normal magnetization curve of ferromagnetic material.", "image_strategy": "GEN_PROMPT"}, {"part": "b", "unit": null, "marks": 7, "has_or_choice": false, "image_details": null, "question_text": "Explain in detail the Applications of DC Machines.", "image_strategy": null}, {"part": "a", "unit": null, "marks": 7, "has_or_choice": false, "image_details": "Output characteristics curves (Ic vs Vce) for an NPN transistor in Common Emitter (CE) configuration, showing different base currents (Ib).", "question_text": "Draw and explain the output characteristic of a NPN transistor operation in CE configuration.", "image_strategy": "GEN_P